import{_ as o,c as e,o as r,ai as i}from"./chunks/framework.TS84ywiI.js";const s=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Dubbo/architectureDesign/Dubbo整体架构.md","filePath":"Dubbo/architectureDesign/Dubbo整体架构.md"}'),b={name:"Dubbo/architectureDesign/Dubbo整体架构.md"};function t(n,a,d,u,l,c){return r(),e("div",null,a[0]||(a[0]=[i('<h2 id="项目结构" tabindex="-1">项目结构 <a class="header-anchor" href="#项目结构" aria-label="Permalink to &quot;项目结构&quot;">​</a></h2><p>首先从 GitHub 上 clone 下来 Dubbo 项目，我们根据其中各子项目的项目名，也能大概猜出来各个模块的作用。</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/Dubbo/dubbo%E9%A1%B9%E7%9B%AE%E7%BB%93%E6%9E%84.png" alt="avatar"></p><h3 id="dubbo-common" tabindex="-1">dubbo-common <a class="header-anchor" href="#dubbo-common" aria-label="Permalink to &quot;dubbo-common&quot;">​</a></h3><p>公共逻辑子项目，定义了各子项目中 通用的 组件 和 工具类，如：IO、日志、配置处理等。</p><h3 id="dubbo-rpc" tabindex="-1">dubbo-rpc <a class="header-anchor" href="#dubbo-rpc" aria-label="Permalink to &quot;dubbo-rpc&quot;">​</a></h3><p>分布式协调服务框架的核心，该模块定义了 RPC 相关的组件，包括 服务发布、服务调用代理、远程调用结果、RPC 调用网络协议，RPC 调用监听器和过滤器等等。该模块提供了默认的 基于 dubbo 协议的实现，还提供了 hessian、http、rmi、及 webservice 等协议的实现，能够满足绝大多数项目的使用需求，另外 还提供了对自定义协议的扩展。</p><h3 id="dubbo-registry" tabindex="-1">dubbo-registry <a class="header-anchor" href="#dubbo-registry" aria-label="Permalink to &quot;dubbo-registry&quot;">​</a></h3><p>注册中心子项目，它是 RPC 中 consumer 服务消费者 和 provider 服务提供者 两个重要角色的协调者，该子项目定义了核心的 注册中心组件，提供了 mutilcast、redis 和 zookeeper 等多种方式的注册中心实现，用于不同的使用场景。当然，几乎所有的项目都会选择基于 zookeeper 的实现。</p><h3 id="dubbo-remoting" tabindex="-1">dubbo-remoting <a class="header-anchor" href="#dubbo-remoting" aria-label="Permalink to &quot;dubbo-remoting&quot;">​</a></h3><p>远程通讯子项目，RPC 的实现基础就是远程通讯，consmer 要调用 provider 的远程方法必须通过 远程通讯实现。该模块定义了远程传输器、endpoint 终端、客户端、服务端、编码解码器、数据交换、缓冲区、通讯异常定义 等核心组件。他是对于远程网络通讯的抽象，提供了诸如 netty、mina、http 等 协议和技术框架的实现方式。</p><h3 id="dubbo-monitor" tabindex="-1">dubbo-monitor <a class="header-anchor" href="#dubbo-monitor" aria-label="Permalink to &quot;dubbo-monitor&quot;">​</a></h3><p>监控子项目，该模块可以监控服务调用的各种信息，例如调用耗时、调用量、调用结果等等，监控中心在调用过程中收集调用的信息，发送到监控服务，在监控服务中可以存储这些信息，对这些数据进行统计分析 和 展示。dubbo 默认提供了一个实现，该实现非常简单，只是作为默认的实现范例，生产环境使用价值不高，往往需要自行实现。</p><h3 id="dubbo-container" tabindex="-1">dubbo-container <a class="header-anchor" href="#dubbo-container" aria-label="Permalink to &quot;dubbo-container&quot;">​</a></h3><p>容器子项目，是一个独立的容器，以简单的 Main(类) 加载 Spring 启动，因为服务通常不需要 Tomcat/JBoss 等 Web 容器的特性，没必要用 Web 容器去加载服务。</p><h3 id="dubbo-config" tabindex="-1">dubbo-config <a class="header-anchor" href="#dubbo-config" aria-label="Permalink to &quot;dubbo-config&quot;">​</a></h3><p>配置中心子项目，该模块通过 配置信息，将 dubbo 组件的各个模块整合在一起，给 框架的使用者 提供 可配置的、易用的 分布式服务框架。它定义了面向 dubbo 使用者的各种信息配置，比如服务发布配置、方法发布配置、服务消费配置、应用程序配置、注册中心配置、协议配置、监控配置等等。</p><h3 id="dubbo-cluster" tabindex="-1">dubbo-cluster <a class="header-anchor" href="#dubbo-cluster" aria-label="Permalink to &quot;dubbo-cluster&quot;">​</a></h3><p>集群子项目，将多个服务提供方伪装为一个提供方，包括：负载均衡、容错、路由等，集群的地址列表可以是静态配置的，也可以是由注册中心下发。</p><h3 id="dubbo-admin" tabindex="-1">dubbo-admin <a class="header-anchor" href="#dubbo-admin" aria-label="Permalink to &quot;dubbo-admin&quot;">​</a></h3><p>该子项目是一个 web 应用，可以独立部署，用于管理 dubbo 服务，该管理应用可以连接注册中心，读取和更新 注册中心中的内容。</p><h2 id="实现原理" tabindex="-1">实现原理 <a class="header-anchor" href="#实现原理" aria-label="Permalink to &quot;实现原理&quot;">​</a></h2><h3 id="角色类型与运行原理" tabindex="-1">角色类型与运行原理 <a class="header-anchor" href="#角色类型与运行原理" aria-label="Permalink to &quot;角色类型与运行原理&quot;">​</a></h3><p>一个 Dubbo 项目 的角色主要分为如下五种。</p><ul><li>Provider：服务提供方；</li><li>Consumer：服务消费方；</li><li>Registry：服务注册与发现的注册中心；</li><li>Container：服务运行容器；</li><li>Monitor：统计服务的调用次数、调用时间 的监控中心。</li></ul><p>其运行原理如下图所示。</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/Dubbo/Dubbo%E5%B7%A5%E4%BD%9C%E5%8E%9F%E7%90%86%E5%9B%BE.png" alt="avatar"></p><h3 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h3><p>最后总结下其工作原理。</p><ol><li>服务导出：服务提供方 导出服务，监听服务端口；</li><li>服务注册：服务提供方 注册服务信息到注册中心；</li><li>服务订阅：服务消费方 订阅关注的服务；</li><li>服务发现：当服务地址发生变更时，注册中心通知服务消费端；</li><li>远程服务调用 ：根据负载均衡策略 选择服务地址，直接调用；</li><li>监控：监控器 收集和展示 服务提供方、服务消费方之间 的服务调用统计信息 。</li></ol>',30)]))}const p=o(b,[["render",t]]);export{s as __pageData,p as default};
